 p_FailoverMaxAttempts := p_FailoverMaxAttempts_414bf114, p_FailoverDelaySeconds := p_FailoverDelaySeconds_414bf114, p_FailoverModelStrategy := p_FailoverModelStrategy_414bf114, p_FailoverErrorScope := p_FailoverErrorScope_414bf114, p_EffortLevel := p_EffortLevel_414bf114, p_ID := p_ID_414bf114);
