-- Save MJ: Template Contents (core SP call only)
DO $$
DECLARE
  p_TemplateID_95c1900f UUID;
  p_TypeID_95c1900f UUID;
  p_TemplateText_95c1900f TEXT;
  p_Priority_95c1900f INTEGER;
  p_IsActive_95c1900f BOOLEAN;
